const request = $json.body ?? $json;
const headers = $json.headers ?? {};
const configuredSecret = 'qr-local-ai-test-secret';
const incomingSecret = String(headers['x-quicreply-webhook-secret'] || headers['X-Quicreply-Webhook-Secret'] || '').trim();

const contextQuality = request.contextQuality ?? {};
const businessContext = request.businessContext ?? {};
const businessDescription = typeof businessContext.businessDescription === 'string' ? businessContext.businessDescription.trim() : '';
const productsServices = typeof businessContext.productsServices === 'string' ? businessContext.productsServices.trim() : '';
const aiKnowledge = request.aiKnowledge ?? {};
const staffDisplayName = typeof request.staff?.displayName === 'string' ? request.staff.displayName.trim() : '';

let guardMessage = '';
if (configuredSecret && incomingSecret !== configuredSecret) {
  guardMessage = 'Unauthorized AI test webhook request.';
} else if (!contextQuality.isReady || !businessDescription || !productsServices) {
  guardMessage = 'Complete Jennifer setup before testing.';
}

const history = Array.isArray(request.conversationHistory) ? request.conversationHistory : [];
const recentHistory = history
  .filter((entry) => entry && typeof entry.text === 'string' && entry.text.trim())
  .slice(-6)
  .map((entry) => `${entry.role || 'user'}: ${entry.text.trim()}`);

const responseStyle = typeof businessContext.responseStyle === 'string' && businessContext.responseStyle.trim()
  ? businessContext.responseStyle.trim()
  : 'professional';
const aiLanguage = typeof businessContext.aiLanguage === 'string' && businessContext.aiLanguage.trim()
  ? businessContext.aiLanguage.trim()
  : 'english';
const organizationName = typeof request.organization?.name === 'string' && request.organization.name.trim()
  ? request.organization.name.trim()
  : 'the business';
const customerPrompt = typeof request.prompt === 'string' ? request.prompt.trim() : '';

const prompt = [
  'You are Jennifer, the QuicReply AI assistant.',
  'This is a TEST SANDBOX ONLY.',
  'You must never claim that you sent a message, completed a handoff, attached proof, generated a screenshot, updated a CRM, or performed any live action.',
  'If the user asks you to send, prove, confirm delivery, or show evidence, clearly say this sandbox can only draft the reply and cannot perform the action.',
  'Do not invent pricing, guarantees, AI credits, usage allowances, or product capabilities that are not provided below.',
  'If information is missing, say so briefly and offer a safe next step.',
  staffDisplayName ? `Workspace owner reference: ${staffDisplayName}. Use this only when directly relevant.` : '',
  `Business: ${businessDescription || 'Not provided.'}`,
  `Products/services: ${productsServices || 'Not provided.'}`,
  `Pricing and plans: ${typeof aiKnowledge.pricingAndPlans === 'string' ? aiKnowledge.pricingAndPlans.trim() : 'Not provided.'}`,
  `Seats, usage, and limits: ${typeof aiKnowledge.seatsAndLimits === 'string' ? aiKnowledge.seatsAndLimits.trim() : 'Not provided.'}`,
  `Core features: ${typeof aiKnowledge.coreFeatures === 'string' ? aiKnowledge.coreFeatures.trim() : 'Not provided.'}`,
  `Product pages: ${typeof aiKnowledge.productPages === 'string' ? aiKnowledge.productPages.trim() : 'Not provided.'}`,
  `Policies and FAQs: ${typeof aiKnowledge.policiesAndFaqs === 'string' ? aiKnowledge.policiesAndFaqs.trim() : 'Not provided.'}`,
  `Organization: ${organizationName}`,
  `Response style: ${responseStyle}`,
  `Language: ${aiLanguage}`,
  `Conversation history:\n${recentHistory.length ? recentHistory.join('\n') : 'No prior conversation.'}`,
  `Customer message: ${customerPrompt || 'No customer message.'}`,
  'Reply in 2-5 sentences.',
  'Return plain answer text only.'
].filter(Boolean).join('\n');

return [{
  json: {
    guardMessage,
    openclawBaseUrl: 'http://127.0.0.1:18789',
    openclawToken: 'qr-local-openclaw-token-20260607',
    openclawModel: 'openclaw/ai-test',
    openclawPrompt: prompt
  }
}];

if ($json.guardMessage) {
  return [{
    json: {
      message: $json.guardMessage,
      route: 'n8n.guard',
      warnings: []
    }
  }];
}

if ($json.error) {
  return [{
    json: {
      message: 'Jennifer runtime could not be reached.',
      route: 'openclaw.ai-test',
      warnings: ['runtime_unreachable']
    }
  }];
}

const output = Array.isArray($json.output) ? $json.output : [];
const text = output
  .flatMap((entry) => Array.isArray(entry.content) ? entry.content : [])
  .find((content) => content?.type === 'output_text' && typeof content.text === 'string')
  ?.text
  ?.trim();

const looksInvalid = !text || text.startsWith('```') || text.includes('<tool') || text.includes('"tool_name"');
if (looksInvalid) {
  return [{
    json: {
      message: 'Jennifer runtime failed to produce a response.',
      route: 'openclaw.ai-test',
      warnings: ['runtime_invalid_output']
    }
  }];
}

const fakeActionPatterns = [
  /\bi(?:'ve| have)? sent\b/i,
  /\bi(?:'ll| will) send\b/i,
  /\bsent (?:it|that|the follow-?up)\b/i,
  /\bhere(?:'s| is) (?:a )?screenshot\b/i,
  /\bproof\b/i,
  /\bi(?:'ve| have)? attached\b/i,
  /\bit has been sent\b/i,
];

if (fakeActionPatterns.some((pattern) => pattern.test(text))) {
  return [{
    json: {
      message: 'I can’t actually send messages, attach proof, or complete live actions from this test sandbox. I can draft the exact reply Jennifer should send instead.',
      route: 'openclaw.ai-test',
      warnings: ['sandbox_claim_blocked']
    }
  }];
}

return [{
  json: {
    message: text,
    route: 'openclaw.ai-test',
    warnings: []
  }
}];
